-- Enrichment marathon batch: Commure, Compare JSON, Compass, Compology, Components.studio, Composio, Conky, ConnectyCube

-- ── Commure ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Commure is a healthcare technology company that builds an AI-powered operating system, CommureOS, for hospitals and health systems. It provides ambient clinical documentation, revenue cycle management, patient engagement, remote monitoring, mobile EHR access, and staff safety tools used across hundreds of care facilities in the United States.$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise pricing, sales-led (quote-based, contracted with health systems)$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed; enterprise contracts negotiated per health system$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Roughly 700 to 1,500 employees (estimates vary by source, larger after the Athelas and Augmedix combinations)$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Commure Review: Healthcare AI Platform Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Commure is an AI-powered healthcare operating system for clinical documentation, revenue cycle, and patient workflows. See features, pricing, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Commure is a privately held healthcare technology company headquartered in Mountain View, California, founded in 2017. It builds CommureOS, a unified software platform that health systems use to run clinical, administrative, and financial workflows on a single operating layer rather than stitching together disconnected point solutions. In October 2023, Commure announced a combination with Athelas, a healthcare workflow automation company, in a deal backed by a 70 million dollar investment from General Catalyst that valued the combined entity at roughly 6 billion dollars; the merged company retained the Commure name and is led by Athelas co-founder Tanay Tandon as CEO. By 2026 Commure's valuation had grown to approximately 7 billion dollars, with backing from investors including General Catalyst, Sequoia Capital, NVIDIA, and Y Combinator. Commure has also expanded through further acquisitions, including a deal to acquire Augmedix, a NASDAQ-listed ambient AI documentation company, taking it private and further building out its AI capabilities in healthcare. As of 2026 the combined company reaches more than 160,000 clinicians and staff across more than 500 care facilities in the United States. Commure's product suite spans multiple categories built on top of CommureOS: Ambient AI for real-time clinical documentation during patient visits, Dictation for voice-to-text charting, Call Center Agents for automated scheduling and call routing, Orchestrator for AI-assisted referral intake, RCM (Revenue Cycle Management) for medical billing automation and claims workflows, Engage for patient experience and care coordination, Commure Pro as a broader clinical intelligence platform for hospital operations, Strongline for staff safety alerting and nurse badging, and Athelas Home for point-of-care blood diagnostics. The platform is aimed at hospital and health system IT leaders, revenue cycle teams, clinicians, and care coordinators who need to reduce administrative burden, cut documentation time, and improve throughput without replacing their core electronic health record (EHR) system. Commure integrates with existing EHR systems rather than replacing them, positioning itself as an infrastructure and automation layer that sits above legacy hospital software. Pricing is not publicly published; Commure sells through enterprise sales cycles with contracts negotiated individually per health system based on facility size, modules selected, and integration scope. Competitors in adjacent categories include ambient AI scribe vendors like Nuance DAX and Abridge, revenue cycle vendors like Waystar, and broader health IT platforms. Because Commure operates in a regulated industry, its products are built with HIPAA compliance and clinical data security as core requirements. Buyers evaluating Commure should expect a multi-stakeholder enterprise sales process involving IT, compliance, clinical leadership, and finance, typical of large-scale health system software procurement, and should request references from health systems of comparable size before committing to a full CommureOS deployment.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ede5e1e6-847c-4d18-a668-f60f02db6d58';

