-- ── Compass ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Compass, Inc. (NYSE: COMP) is a publicly traded, technology-enabled residential real estate brokerage headquartered in New York City. Founded in 2012, it combines a proprietary software platform, including CRM, marketing, and AI tools, with a nationwide network of real estate agents, and completed an all-stock combination with Anywhere Real Estate in January 2026.$q$, short_description),
  pricing_model = COALESCE($q$Commission-based real estate brokerage; technology platform is bundled into the agent commission split rather than sold as separate software$q$, pricing_model),
  starting_price = COALESCE($q$No separate software fee; agents operate on negotiated commission splits, generally without an additional technology fee$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Approximately 3,200 corporate employees, plus tens of thousands of affiliated real estate agents$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Compass Real Estate: Platform, Pricing, and Agent Model Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Compass (NYSE: COMP) is a tech-enabled real estate brokerage with an in-house CRM and marketing platform. Learn how its agent model and pricing work.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Compass, Inc. is a publicly traded, technology-enabled residential real estate brokerage that trades on the New York Stock Exchange under the ticker COMP. It was founded in October 2012 in New York City as Urban Compass by Ori Allon, Robert Reffkin, and Avi Dorfman, and is led by co-founder and CEO Robert Reffkin. Note that the name Compass is used by many unrelated products, including JetBrains Compass and various browser and navigation tools; this entry refers specifically to Compass Inc., the real estate brokerage. Compass operates as an owned-brokerage real estate company built around a proprietary technology platform rather than a traditional franchise model. Its software, marketed to agents as the Compass Platform and more recently unified under Compass One (rolled out starting in 2024), bundles a customer relationship management system, a visual client collaboration tool called Collections, a Marketing Center for creating branded digital and print campaigns, a Business Tracker for pipeline and performance analytics, and AI features that draft listing descriptions, assemble comparative market analyses (CMAs), and generate buyer and seller follow-up communications. Compass also offers integrated title, escrow, and mortgage services through affiliated businesses. Unlike a typical software company, Compass does not charge agents a separate line-item fee for its technology; the platform is included as part of the agent's negotiated commission split, with no additional technology surcharge layered on top. Commission splits at Compass are individually negotiated based on the agent's production level, market, and team structure, and some top-producing agents have negotiated splits as favorable as 90/10 in their favor. As of 2026, Compass has grown substantially: in January 2026 it completed an all-stock combination with Anywhere Real Estate Inc. (parent of brands including Coldwell Banker, Century 21, and Sotheby's International Realty), creating a global real estate services company with a presence in every major US city and roughly 120 countries and territories. Following this combination, Compass has approximately 33,000 agents operating directly under the Compass brand across more than 400 offices in 96 markets, and approximately 340,000 agents and associates, generally independent contractors, across its combined and franchised network. As of mid-2026, Compass reported trailing twelve-month revenue of approximately 7.0 billion dollars and a market capitalization of roughly 8.9 billion dollars, with its stock trading around 11 dollars per share in July 2026. Compass positions itself as the largest residential real estate brokerage in the United States by sales volume. Its target customers are real estate agents seeking an integrated technology stack bundled into their brokerage relationship, and home buyers and sellers who work with Compass-affiliated agents and benefit from tools like Compass Collections for browsing curated listings. Competitors in the tech-enabled brokerage space include eXp Realty, Real Brokerage, and Side, while traditional competitors include Coldwell Banker, Keller Williams, and RE/MAX, several of which are now part of the combined Compass-Anywhere entity following the 2026 merger.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b7b5cb9-c8e4-42b5-837c-28f52ca5aaa3';

