-- ── Compology ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Compology developed AI-powered, camera-based smart waste and recycling monitoring technology that tracks dumpster fill levels and contamination for haulers, property managers, and Fortune 500 companies. Founded in San Francisco around 2012 to 2013, Compology was acquired by RoadRunner Recycling in October 2022, not by Rubicon Technologies, and its technology now operates as part of RoadRunner's waste data platform.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise B2B, quote-based hardware plus software subscription (historically; now offered through RoadRunner Recycling)$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed; historically sold as a custom quote combining camera hardware installation and a recurring monitoring subscription$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Formerly an independent startup; now integrated into RoadRunner Recycling, which had roughly 600 employees around the time of the acquisition$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (now part of RoadRunner Recycling, headquartered in Pittsburgh, Pennsylvania)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Compology: Smart Dumpster Monitoring, Acquired by RoadRunner$q$, seo_title),
  seo_meta_description = COALESCE($q$Compology built AI camera sensors for waste and recycling monitoring. Learn what it does, its acquisition history, and current status under RoadRunner.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Compology was a San Francisco-based startup that built AI-powered, camera-based sensors installed inside commercial dumpsters and recycling containers to monitor fill levels, detect contamination, and verify waste hauling service. The company was founded by Jason Gates and Benjamin Chehebar, with sources placing the founding around 2012 to 2013 and its first commercial camera-based monitoring deployment occurring in 2014 at the University of California, Santa Cruz. Compology operated as a certified B Corporation and described itself as the world's largest waste and recycling smart metering technology company, serving customers including Fortune 500 companies, property management firms, waste hauling companies, waste brokers, cities, and universities. Its core technology combined in-dumpster cameras with computer vision and AI to generate a Contamination Score that flagged when recyclable containers had non-recyclable material mixed in, along with fill-level data that let haulers optimize pickup schedules and property managers verify that a hauler had actually emptied a container as billed, a use case sometimes referred to as service verification. The technology attracted mainstream press attention, including coverage of McDonald's restaurants installing Compology cameras in dumpsters to track and reduce waste and improve sustainability reporting. It is important to correct a common point of confusion: Compology was not acquired by Rubicon Technologies. Instead, Compology was acquired by RoadRunner Recycling, a Pittsburgh-based commercial waste and recycling collection company, in October 2022. RoadRunner, founded in 2014, works with third-party haulers across more than 40 major US cities and all 50 states, and it acquired Compology specifically to bring AI-driven smart metering technology in-house and improve waste data collection across its collection network; the acquisition reportedly more than doubled RoadRunner's employee headcount to around 600 employees at the time. As of 2026, Compology no longer operates as an independent company; its technology and team have been absorbed into RoadRunner Recycling's broader waste and recycling data platform. Separately, Rubicon Technologies, a different waste and recycling technology company, has been divesting parts of its own software and city-services businesses as of early 2026, but this divestiture is unrelated to Compology and should not be confused with the 2022 RoadRunner acquisition. Anyone researching Compology's current ownership or evaluating its technology today should look to RoadRunner Recycling as the operating entity, since Compology as a standalone brand and company has effectively been folded into RoadRunner's operations since the 2022 deal closed.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '224efe76-dd3a-4172-b743-7b0ea83c601a';

