-- ── Components.studio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Components.studio was an online IDE for building, previewing, and testing web components, built by the French design tooling company divRIOTS. It was discontinued on June 1, 2025 along with sibling products Webcomponents.dev and Backlight.dev, as divRIOTS shifted its entire focus to a suite of Figma plugins; the domain now redirects to divriots.com.$q$, short_description),
  pricing_model = COALESCE($q$Discontinued as a standalone product (was previously part of a free and paid Backlight/divRIOTS subscription suite)$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable; product discontinued as of June 1, 2025$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Approximately 17 employees at divRIOTS as of mid-2024$q$, company_size),
  headquarters = COALESCE($q$Paris (Colombes), France$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Components.studio: What It Was and Why It Was Shut Down$q$, seo_title),
  seo_meta_description = COALESCE($q$Components.studio was a web component IDE by divRIOTS, discontinued in June 2025. Learn what it offered and where its technology went.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Components.studio was an online integrated development environment (IDE) built specifically for creating, previewing, and testing web components, marketed with the tagline the Component IDE for Web Platform Developers. It was created by divRIOTS, a French software company founded in 2019 by CEO Georges Gomes along with co-founders Francois Valdy and Gregory Quinio, headquartered near Paris in Colombes, France. divRIOTS raised a 3 million dollar financing round led by XAnge, joined by angel investors including Laurent Useldinger, Thibaud Elziere, Eduardo Ronzano, Nicolas Steegmann, Frederic Montagnon, and Julien Romanetto, and as of mid-2024 the company had around 17 employees. Components.studio was one of three closely related developer tools that divRIOTS operated together: Components.studio and its sibling Webcomponents.dev served as browser-based coding environments for building and testing individual web components across many different frameworks and libraries, including plain HTMLElement, Atomico, Lit, TypeScript-based approaches, Omi, FAST, Haunted, Salesforce Lightning Web Components (LWC), Preact, Stencil, Svelte, and Vue 3, letting developers compare coding style, bundle size, and runtime performance of the same component built multiple ways. The third product, Backlight.dev, was positioned as a more complete, code-side design system SaaS platform for front-end teams, letting design and engineering collaborate on a shared component library with features like visual pull request rendering. As of June 1, 2025, divRIOTS officially shut down all three of these products, Components.studio, Webcomponents.dev, and Backlight.dev, citing the growing success of a separate line of business: a suite of more than 20 Figma plugins under the divRIOTS brand that automate design-to-code workflows, such as importing HTML, images, and various file formats (including PDF, PSD, Adobe Illustrator, and CAD or 3D models) directly into Figma, along with AI-assisted image editing tools like background removal and upscaling, plus APIs for programmatic file conversion. The company's stated rationale was to focus all engineering effort on the Figma plugin ecosystem rather than continuing to maintain three separate online IDE products. As of 2026, visiting components.studio redirects to divriots.com, where the company markets its current suite of Figma plugins and browser extension under the positioning statement We Supercharge Figma, offering a single unified subscription called divRIOTS ONE that bundles access to its Figma tooling. One notable exception to the shutdown was LWC.studio, a dedicated online IDE specifically for editing Salesforce Lightning Web Components using the Lightning Design System, which divRIOTS introduced as a narrower successor covering at least part of the use case that the broader Components.studio and Webcomponents.dev platforms previously served. Anyone researching Components.studio today should treat it as a discontinued product: it can no longer be used for live component development or preview, and prospective users looking for a similar web component development environment should look at current alternatives or consider divRIOTS' narrower LWC.studio offering if their use case is specifically Salesforce Lightning Web Components.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ac6b6746-2fa3-4120-a29b-219a3772b4df';

