-- ── Composio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Composio is a developer platform that gives AI agents and large language models secure, pre-built access to more than a thousand external apps and APIs, handling authentication, tool orchestration, and sandboxed execution. Founded in 2023 and headquartered in San Francisco, it raised a 25 million dollar Series A in 2025 led by Lightspeed Venture Partners.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, usage-based subscription tiers priced by monthly tool calls, plus custom Enterprise pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available (20,000 tool calls per month); paid plans start at 29 dollars per month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Roughly 70 employees (as of 2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Composio Pricing and Features: AI Agent Integration Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Composio connects AI agents to 1,000+ apps with managed auth and tool orchestration. See pricing tiers, features, and how it compares.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Composio is an infrastructure platform, founded in 2023 and headquartered in San Francisco, California, that solves a specific problem for developers building AI agents: connecting large language models to external applications and APIs without manually implementing OAuth flows, rate limiting, and custom API wrappers for every service an agent needs to use. The platform provides access to more than a thousand pre-built integrations, referred to as toolkits, covering common business and developer tools, and it manages the authentication layer (OAuth 2.0, API keys, and JWT tokens), encrypted credential storage, and sandboxed execution environments so agents can call external tools safely without direct access to raw credentials. Composio supports the Model Context Protocol (MCP), a standard for connecting AI assistants to external tools and data sources, and offers an MCP Gateway that lets developers expose Composio's toolkits to MCP-compatible clients such as Cursor, Windsurf, and Claude. In February 2026, Composio open-sourced its Agent Orchestrator, a framework intended to move agent development beyond simple ReAct-style reason-and-act loops toward more structured, stateful multi-agent workflows, reflecting the company's broader ambition to provide not just tool connectivity but also orchestration infrastructure for production AI agents. Composio is headquartered at 970 Hayes Street in San Francisco and, as of mid-2026, has a workforce reported at approximately 70 employees, though some business directories list a smaller range of 11 to 50 employees, reflecting the natural lag in third-party employee counts for a fast-growing startup. The company raised a 25 million dollar Series A round in July 2025, led by Lightspeed Venture Partners, with participation from SV Angel, Blitzscaling Ventures, Operator Partners, Agent Fund (backed by Yohei Nakajima), and existing investors Elevation Capital and Together Fund. Notable angel investors include Guillermo Rauch, CEO of Vercel, Dharmesh Shah, co-founder and CTO of HubSpot, Gokul Rajaram, and Soham Mazumdar, co-founder of Rubrik, bringing Composio's total disclosed funding to approximately 29 million dollars. Composio's pricing follows a usage-based tiered model built around monthly tool calls. The Free tier includes 20,000 tool calls per month with community support at no cost. The next tier, priced at 29 dollars per month, includes 200,000 tool calls per month with email support, and additional usage beyond the included allotment is billed at roughly 0.299 dollars per 1,000 calls. A higher tier priced at 229 dollars per month includes 2 million tool calls per month with Slack-based support, with overage billed at roughly 0.249 dollars per 1,000 calls. An Enterprise tier is available with custom quoted pricing that adds dedicated user accounts, custom SLAs, SOC 2 compliance support, adjustable API volume, and VPC or on-premises deployment options for organizations with stricter security or compliance requirements. Composio's target customers are engineering teams building AI agents, whether internal automation agents, customer-facing AI assistants, or agentic products, who want to avoid building and maintaining custom integration code for every third-party service their agent needs to call. It competes in the emerging category of agent-native integration platforms, distinct from traditional automation and integration-platform-as-a-service (iPaaS) tools like Zapier, which were designed primarily for human-triggered workflow automation rather than autonomous AI agent tool calling.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c4490765-45f7-48dc-ab27-e987dfb6cd75';

