-- ── Conky ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Conky is a free, open-source, lightweight desktop system monitor for Linux, FreeBSD, and OpenBSD that displays real-time system statistics like CPU, memory, disk, network, and battery status directly on the desktop. Originally forked from Torsmo in 2005 by Brenden Matthews, it is highly configurable and extensible with built-in Lua scripting.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$Not applicable; open-source community project maintained by volunteer contributors, not a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable; distributed open-source project with no corporate headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Conky: Free Lightweight System Monitor for Linux Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$Conky is a free, open-source desktop system monitor for Linux and BSD. See its features, configuration options, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Conky is a free and open-source desktop system monitor originally built for the X Window System, with support extended over time to Wayland and other display environments, and it runs on Linux, FreeBSD, and OpenBSD. Development began in 2005 when Brenden Matthews forked the project from an earlier tool called Torsmo to create a more customizable and extensible system monitor. Between 2005 and 2010, the project matured through versions 1.0 through 1.7.2, adding core capabilities like enhanced network monitoring and basic scripting support. Conky is licensed under a mix of terms reflecting its history: the original torsmo-derived code remains BSD licensed, while new code contributed to Conky since the fork has been released under the GNU General Public License version 3 (GPL 3.0). The current active codebase is maintained on GitHub under the repository brndnmtthws/conky, described as a light-weight system monitor for X, Wayland, and other display environments. As an open-source community project rather than a commercial company, Conky has no headquarters, no disclosed employee count, and no pricing plans; it is free to download, use, and modify by anyone under its open-source licenses. Functionally, Conky displays real-time system information directly on the desktop as unobtrusive text or graphical widgets, rather than in a separate application window with a graphical toolkit. It can monitor CPU usage and temperature, memory and swap usage, disk storage, network interface activity, battery power levels, running processes, system uptime, and incoming system messages. Beyond core hardware and OS metrics, Conky supports monitoring for email inboxes, Arch Linux package update availability, and popular music players including MPD, XMMS2, BMPx, and Audacious, as well as weather updates and news headlines when configured with appropriate data sources or scripts. A defining technical characteristic of Conky is that it draws its output directly in an X window rather than relying on a high-level widget toolkit like GTK or Qt, which keeps its resource consumption relatively low compared to more heavyweight desktop widget systems, making it popular among users who want detailed system information without a heavy performance cost. Conky is extensible through built-in Lua scripting support, allowing advanced users to build custom modules, animations, and data sources beyond the metrics Conky tracks natively, as well as through integration with external scripts and programs written in any language that can output text Conky can display. Configuration is handled through a text-based configuration file, giving users fine-grained control over layout, fonts, colors, update intervals, and which system metrics are displayed, though this text-based approach means new users typically face a steeper learning curve than point-and-click widget tools. Conky has been recognized in the Linux community for its quality and utility, with Linux Magazine describing it as one of the best-maintained and most useful programs in the open-source world. It is commonly used by Linux desktop enthusiasts, particularly those who customize their desktop environment or window manager setup, to display an at-a-glance system dashboard directly on their wallpaper or desktop background. Typical alternatives in the same space include Conky's own ancestor Torsmo, as well as other desktop widget and system monitoring tools like GKrellM and various desktop-environment-specific system monitor applets, though Conky remains distinctive for its deep configurability and low resource footprint.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '383f828c-a6f6-416b-a1d7-5263c0b93d24';

