-- ── ConnectyCube ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ConnectyCube is a backend-as-a-service platform that provides ready-made SDKs and APIs for in-app chat, peer-to-peer and group video calling, and push notifications. Founded in 2018 and headquartered in Berlin, Germany, it supports iOS, Android, React Native, Flutter, Cordova, NativeScript, and Web, and offers tiered pricing from a free plan up to an Enterprise plan with HIPAA compliance.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, tiered monthly subscription based on active users and storage, plus a custom Enterprise tier$q$, pricing_model),
  starting_price = COALESCE($q$Free tier available for up to 1,000 users; paid plans start at 39 dollars per month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Small to mid-size team (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ConnectyCube Pricing and Features: Chat and Video Calling API$q$, seo_title),
  seo_meta_description = COALESCE($q$ConnectyCube offers chat, video calling, and push notification SDKs for developers. Compare pricing tiers, features, and platform support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ConnectyCube is a communications backend-as-a-service (BaaS) platform that gives app developers ready-made SDKs and server-side APIs for adding real-time chat, video and voice calling, and push notifications to their applications without building this infrastructure from scratch. The company was founded on May 9, 2018 and is headquartered in Berlin, Germany. ConnectyCube positions its platform as serving both traditional app developers and, more recently, teams building AI agents that need chat and calling capabilities, reflected in its current tagline describing itself as offering chat and calling SDKs for developers and AI agents. On the technical side, ConnectyCube provides native and cross-platform SDKs covering iOS (Swift and Objective-C), Android (Java and Kotlin), React Native, Flutter, Apache Cordova, NativeScript, and JavaScript for the Web, giving development teams a consistent integration path regardless of their client technology stack. Core capabilities include one-to-one and group text chat with typing indicators and delivery receipts, peer-to-peer and multi-party (conference) audio and video calling, push notification delivery, user authentication and authorization, chat file and media attachments, end-to-end encryption for sensitive communications, and automated chat bot support for building conversational experiences. ConnectyCube's pricing follows a freemium, tiered subscription model priced primarily around the number of monthly active users and storage allowance, rather than a flat per-seat fee. The Free plan supports up to 1,000 users with 5 gigabytes of storage, a 1-month message retention window, peer-to-peer audio and video calls, client-side video call recording, and community support, at no cost. The Hobby plan is priced at 39 dollars per month and raises the ceiling to 10,000 users, 10 gigabytes of storage, and 3 months of retention. The Advanced plan, at 99 dollars per month, supports 25,000 users, 25 gigabytes of storage, 6 months of retention, and adds multi-party conference calling on top of peer-to-peer calls. The Pro plan starts from 199 dollars per month, supports 50,000 users (expandable through additional purchases), 50 gigabytes of storage, custom retention, and adds server-side call recording along with priority community and email support. At the top end, the Enterprise plan starts from 599 dollars per month and includes unlimited storage, custom user limits, data encryption, HIPAA compliance support, a 99.9 percent uptime service level agreement, a dedicated account manager, and dedicated server hosting, making it suitable for healthcare and other regulated industries that need to handle sensitive communications data. Across all tiers, ConnectyCube includes core chat, group messaging, meeting reminder, and administration API access, with higher tiers unlocking more capacity, more advanced recording and compliance features, and higher-touch support. ConnectyCube's target customers are software development teams that need to embed real-time communication features, such as in-app customer support chat, telehealth video visits, marketplace buyer-seller messaging, or social and dating app chat and calling, into their own products without building and maintaining this real-time infrastructure themselves. Its Berlin base and HIPAA-capable Enterprise tier make it a relevant option for companies serving European and US markets with regulated communications requirements, and its multi-platform SDK coverage makes it a practical choice for teams shipping the same communication features across web, iOS, Android, and cross-platform frameworks like React Native and Flutter simultaneously.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4bb7cefd-1923-4415-8bca-87e2a1517d8e';

